extends Node2D

@export var GRASS_EFFECT: PackedScene

@onready var hurtbox: Hurtbox = $Hurtbox

func _ready() -> void:
	hurtbox.hurt.connect(_on_hurt)

func _on_hurt(other_hitbox: Hitbox) -> void:
	var grass_effect_instance = GRASS_EFFECT.instantiate()
	get_tree().current_scene.add_child(grass_effect_instance)
	grass_effect_instance.global_position = global_position
	# Avisa que a grama foi cortada
	GameEvents.grass_cut.emit(15)
	queue_free()

extends Node2D

@export_group("Configurações de Spawn")
@export var enemy_scene: PackedScene      # Qual inimigo spawnar (Arraste o .tscn do Morcego aqui)
@export var max_enemies: int = 5          # Limite de monstros ativos para este spawner
@export var spawn_cooldown: float = 5.0   # Tempo em segundos entre cada nascimento
@export var spawn_radius: float = 60.0    # Raio de dispersão (para não nascerem um em cima do outro)

@export_group("Configurações da Área")
@export var area_level: int = 1           # Nível que os monstros desta área terão

@onready var timer: Timer = $Timer

var current_enemy_count: int = 0

func _ready() -> void:
	# Configura o cronômetro com o tempo definido
	timer.wait_time = spawn_cooldown
	timer.timeout.connect(_on_timer_timeout)
	timer.start()

func _on_timer_timeout() -> void:
	if current_enemy_count < max_enemies:
		spawn_enemy()

func spawn_enemy() -> void:
	if not enemy_scene: return

	var enemy = enemy_scene.instantiate() as Enemy
	if enemy:
		# Define o nível do monstro baseado na configuração do Spawner
		enemy.enemy_level = area_level

		# Calcula uma posição aleatória dentro do raio para dispersão
		var random_offset = Vector2(randf_range(-1, 1), randf_range(-1, 1)).normalized() * randf_range(0, spawn_radius)
		enemy.global_position = global_position + random_offset

		# Conecta o sinal de saída da árvore para saber quando o monstro morreu/sumiu
		enemy.tree_exited.connect(_on_enemy_removed)

		# Adiciona o inimigo à cena principal (não ao spawner, para ele se mover livremente)
		get_parent().add_child.call_deferred(enemy)
		current_enemy_count += 1

func _on_enemy_removed() -> void:
	current_enemy_count -= 1

class_name Hitbox extends Area2D

@export var damage: = 1
@export var knockback_amount: = 200
@export var knockback_direction: Vector2
@export var stores_hit_targets: bool = false

var hit_targets: Array

func clear_hit_targets() -> void:
	hit_targets.clear()

class_name Hurtbox extends Area2D

signal hurt(hitbox: Hitbox)

func _ready() -> void:
	area_entered.connect(_on_area_entered)

func _on_area_entered(area_2d: Area2D) -> void:
	if area_2d is not Hitbox: return
	var hitbox = area_2d as Hitbox
	if self in hitbox.hit_targets: return
	if hitbox.stores_hit_targets: hitbox.hit_targets.append(self)
	hurt.emit(hitbox)

class_name Player extends CharacterBody2D

const SPEED = 100.0
const ROLL_SPEED = 125.0

@export var stats: Stats

var input_vector: = Vector2.ZERO
var last_input_vector: = Vector2.DOWN

@onready var animation_tree: AnimationTree = $AnimationTree
@onready var playback = animation_tree.get("parameters/StateMachine/playback") as AnimationNodeStateMachinePlayback
@onready var hurtbox: Hurtbox = $Hurtbox
@onready var hitbox: Hitbox = $Hitbox
@onready var blink_animation_player: AnimationPlayer = $BlinkAnimationPlayer
@onready var hurt_audio_stream_player: AudioStreamPlayer = $HurtAudioStreamPlayer

func _ready() -> void:
	hurtbox.hurt.connect(take_hit.call_deferred)
	stats.no_health.connect(die)

	# Conecta o sinal de level_up para atualizar o dano
	stats.level_up.connect(_on_level_up)

	# Conecta os sinais globais de experiência
	GameEvents.grass_cut.connect(_on_grass_cut)
	GameEvents.enemy_defeated.connect(_on_enemy_defeated)

	# Define o dano inicial baseado no nível atual
	update_attack_damage()

func _physics_process(delta: float) -> void:
	var state = playback.get_current_node()
	match state:
		"MoveState": move_state(delta)
		"AttackState": pass
		"RollState": roll_state(delta)

func die() -> void:
	hide()
	remove_from_group("player")
	process_mode = Node.PROCESS_MODE_DISABLED

func take_hit(other_hitbox: Hitbox) -> void:
	hurt_audio_stream_player.play()
	stats.health -= other_hitbox.damage
	blink_animation_player.play("blink")
	# CHAMA O NÚMERO FLUTUANTE AQUI (Pode usar uma cor diferente via código se desejar)
	GameEvents.spawn_damage_number(other_hitbox.damage, global_position + Vector2(0, -10))

func _on_level_up(_new_level: int) -> void:
	update_attack_damage()
	print("Level Up! Novo dano: ", hitbox.damage)

func update_attack_damage() -> void:
	# Update dmg ao subir de nivel
	hitbox.damage = 1 + stats.level

func _on_grass_cut(amount: int):
	stats.add_experience(amount)

func _on_enemy_defeated(enemy_level: int, _unused_base_xp: int):
	var level_distance = abs(enemy_level - stats.level)
	var multiplier = clamp(1.0 - (float(level_distance) / 10.0), 0.0, 1.0)
	var final_xp = int(stats.BASE_ENEMY_XP * multiplier)

	stats.add_experience(final_xp)

	# Debug para acompanhar no console
	print("Inimigo Lvl: %d | Distância: %d | Mult: %.2f | XP Ganha: %d" % [enemy_level, level_distance, multiplier, final_xp])

func move_state(delta: float) -> void:
	input_vector = Input.get_vector("move_left", "move_right", "move_up", "move_down")

	if input_vector != Vector2.ZERO:
		last_input_vector = input_vector
		var direction_vector: = Vector2(input_vector.x, -input_vector.y)
		update_blend_positions(direction_vector)

	if Input.is_action_just_pressed("attack"):
		playback.travel("AttackState")

	if Input.is_action_just_pressed("roll"):
		playback.travel("RollState")

	velocity = input_vector * SPEED
	move_and_slide()

func roll_state(delta: float) -> void:
	velocity = last_input_vector.normalized() * ROLL_SPEED
	move_and_slide()

func update_blend_positions(direction_vector: Vector2) -> void:
	animation_tree.set("parameters/StateMachine/MoveState/RunState/blend_position", direction_vector)
	animation_tree.set("parameters/StateMachine/MoveState/StandState/blend_position", direction_vector)
	animation_tree.set("parameters/StateMachine/AttackState/blend_position", direction_vector)
	animation_tree.set("parameters/StateMachine/RollState/blend_position", direction_vector)

extends Enemy # Agora ele estende a nossa nova classe!

const SPEED = 30
const FRICTION = 500

@export var min_range: = 4
@export var max_range: = 128

@onready var sprite_2d: Sprite2D = $Sprite2D
@onready var animation_tree: AnimationTree = $AnimationTree
@onready var playback = animation_tree.get("parameters/StateMachine/playback") as AnimationNodeStateMachinePlayback
@onready var marker_2d: Marker2D = $Marker2D
@onready var navigation_agent_2d: NavigationAgent2D = $Marker2D/NavigationAgent2D

# Substituímos o _ready pelo _child_ready da superclasse
func _child_ready() -> void:
	pass

func _physics_process(delta: float) -> void:
	var state = playback.get_current_node()
	match state:
		"IdleState":
			if can_see_player(max_range):
				playback.travel("ChaseState")

		"ChaseState":
			var player = get_player()
			if player:
				navigation_agent_2d.target_position = player.global_position
				var next_point = navigation_agent_2d.get_next_path_position()
				velocity = global_position.direction_to(next_point - marker_2d.position) * SPEED
				sprite_2d.scale.x = sign(velocity.x) if velocity.x != 0 else sprite_2d.scale.x

			if not is_player_in_range(max_range * 1.5): # Margem para parar de perseguir
				playback.travel("IdleState")

			move_and_slide()

		"HitState":
			velocity = velocity.move_toward(Vector2.ZERO, FRICTION * delta)
			move_and_slide()

# Implementamos o que acontece especificamente com o morcego ao levar hit
func _on_hit_taken(other_hitbox: Hitbox) -> void:
	velocity = other_hitbox.knockback_direction * other_hitbox.knockback_amount
	playback.start("HitState")

class_name Enemy extends CharacterBody2D

# Efeitos comuns
const HIT_EFFECT = preload("uid://bkexmlihmpv74")
const DEATH_EFFECT = preload("uid://ra0kqr8k26y5")

# Configurações de Nível e Ratios
@export_group("Level System")
@export var enemy_level: int = 1
@export var hp_ratio: float = 1.0          # Multiplica o HP base do nível
@export var experience_ratio: float = 1.0  # Multiplica a XP base
@export var vision_ratio: float = 1.0      # Multiplica o alcance da visão

@export_group("Combat")
@export var stats: Stats

# Referências comuns que todo inimigo tem
@onready var hurtbox: Hurtbox = $Hurtbox
@onready var hitbox: Hitbox = $Hitbox
@onready var ray_cast_2d: RayCast2D = $RayCast2D
@onready var center: Marker2D = $Center

# Novas referências para a UI flutuante
@onready var health_bar: ProgressBar = $HealthBarAnchor/ProgressBar
@onready var level_label: Label = $HealthBarAnchor/LevelLabel

func _ready() -> void:
	# Importante: Duplicar o resource para que um morcego não compartilhe HP com outro
	if stats:
		stats = stats.duplicate()
		setup_stats()
		# Conecta a mudança de vida à barra de progresso
		stats.health_changed.connect(_on_health_changed)
		stats.no_health.connect(die)

	if hurtbox:
		hurtbox.hurt.connect(take_hit.call_deferred)

	setup_combat()
	setup_overhead_ui()
	_child_ready()

# Função virtual para ser usada nas subclasses (como o _ready)
func _child_ready() -> void:
	pass

func setup_stats() -> void:
	# Matemática de Escalonamento Base
	# Exemplo: HP base começa em 5 e ganha 1 por nível
	var base_hp_for_level = 4 + enemy_level
	stats.max_health = int(base_hp_for_level * hp_ratio)
	stats.health = stats.max_health

func setup_combat() -> void:
	# Define o dano do inimigo igual ao seu nível
	if hitbox:
		hitbox.damage = enemy_level

func setup_overhead_ui() -> void:
	if health_bar:
		health_bar.max_value = stats.max_health
		health_bar.value = stats.health
	if level_label:
		level_label.text = str(enemy_level)

func _on_health_changed(new_health: int) -> void:
	if health_bar:
		# Atualiza a barra com um Tween opcional para suavidade
		var tween = create_tween()
		tween.tween_property(health_bar, "value", new_health, 0.2)

func get_player() -> Player:
	return get_tree().get_first_node_in_group("player") as Player

func is_player_in_range(custom_range: float) -> bool:
	var player = get_player()
	if player:
		# Aplica o vision_ratio ao alcance solicitado
		var adjusted_range = custom_range * vision_ratio
		return global_position.distance_to(player.global_position) <= adjusted_range
	return false

func can_see_player(max_view_distance: float) -> bool:
	if not is_player_in_range(max_view_distance): return false

	var player = get_player()
	ray_cast_2d.target_position = player.global_position - global_position
	ray_cast_2d.force_raycast_update()
	return not ray_cast_2d.is_colliding()

func take_hit(other_hitbox: Hitbox) -> void:
	var effect = HIT_EFFECT.instantiate()
	get_tree().current_scene.add_child(effect)
	effect.global_position = center.global_position

	stats.health -= other_hitbox.damage

	# CHAMA O NÚMERO FLUTUANTE AQUI
	GameEvents.spawn_damage_number(other_hitbox.damage, global_position + Vector2(0, -10))
	# O knockback ainda é responsabilidade da subclasse processar na física, 
	# mas a força nós recebemos aqui.
	_on_hit_taken(other_hitbox)

# Para a subclasse decidir se entra em estado de Hit ou toca som
func _on_hit_taken(_hb: Hitbox) -> void:
	pass

func die() -> void:
	# A XP agora considera o ratio do monstro específico
	var final_xp_to_emit = int(stats.BASE_ENEMY_XP * experience_ratio)
	GameEvents.enemy_defeated.emit(enemy_level, final_xp_to_emit)

	var death_effect = DEATH_EFFECT.instantiate()
	get_tree().current_scene.add_child(death_effect)
	death_effect.global_position = global_position
	queue_free()

class_name Stats extends Resource

@export var health: = 4 :
	set(value):
		var previous_health = health
		health = clamp(value, 0, max_health)
		if health != previous_health: health_changed.emit(health)
		if health <= 0: no_health.emit()

# Valor base de XP para qualquer inimigo
const BASE_ENEMY_XP = 215
@export var max_health: = 4
@export var level: int = 1
@export var experience: int = 0
@export var experience_required: int = 750

signal health_changed(new_health)
signal no_health()
signal level_up(new_level)
signal xp_changed(current_xp, required_xp)

func add_experience(amount: int):
	experience += amount
	while experience >= experience_required:
		level_up_process()
	xp_changed.emit(experience, experience_required)

func level_up_process():
	experience -= experience_required
	max_health += 1
	health += 1
	level += 1
	# Exemplo de curva: aumenta 10% a cada nível
	experience_required = int(experience_required * 1.1)
	level_up.emit(level)

extends Control

@export var player_stats: Stats

@onready var empty_hearts: TextureRect = $EmptyHearts
@onready var full_hearts: TextureRect = $FullHearts

const TOTAL_WIDTH = 60

func _ready() -> void:
	player_stats.health_changed.connect(animate_heart_change)
	empty_hearts.size.x = TOTAL_WIDTH
	update_heart_width(player_stats.health)

func animate_heart_change(current_health: int) -> void:

	var target_width = (float(current_health) / player_stats.max_health) * TOTAL_WIDTH
	var tween = create_tween()
	tween.tween_property(full_hearts, "size:x", target_width, 0.4)\
		.set_trans(Tween.TRANS_SINE)\
		.set_ease(Tween.EASE_OUT)

func update_heart_width(current_health: int) -> void:
	var target_width = (float(current_health) / player_stats.max_health) * TOTAL_WIDTH
	full_hearts.size.x = target_width

extends Control

@export var player_stats: Stats

@onready var progress_bar: ProgressBar = $ProgressBar
@onready var level_number: Label = $LevelContainer/LevelNumber

func _ready() -> void:
	player_stats.xp_changed.connect(update_xp_bar)
	player_stats.level_up.connect(update_level_display)

	# Inicializa os valores
	update_xp_bar(player_stats.experience, player_stats.experience_required)
	update_level_display(player_stats.level)

func update_xp_bar(current_xp: int, required_xp: int) -> void:
	progress_bar.max_value = required_xp
	progress_bar.value = current_xp

func update_level_display(new_level: int) -> void:
	level_number.text = str(new_level)
